//#region index.ts
/** Copies `content` to the clipboard, which can be text, images or an array of these */
async function clippie(content, { reject } = {}) {
	try {
		const items = [content].flat();
		if (navigator?.clipboard?.write) {
			await navigator.clipboard.write([new ClipboardItem(Object.fromEntries(items.map((c) => {
				const type = c.type || "text/plain";
				return [type, new Blob([c], { type })];
			})))]);
			return true;
		}
		return items.every((c) => typeof c === "string" && fallback(c));
	} catch (err) {
		if (reject) throw err;
		return false;
	}
}
function fallback(content) {
	const el = document.createElement("textarea");
	el.value = content;
	el.readOnly = true;
	el.style.cssText = "clip-path:inset(50%);font-size:12pt;white-space:pre";
	el.ariaHidden = "true";
	document.body.append(el);
	try {
		el.select();
		el.setSelectionRange(0, el.value.length);
		return document.execCommand("copy");
	} finally {
		el.remove();
	}
}

//#endregion
export { clippie };